async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){t.style.display="block",t.innerText="Security error."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count");try{const t=encodeURIComponent("https://api.counterapi.dev/v1/josemanuel31675-cv/visits"),n=await fetch("https://api.allorigins.win/get?url="+t),s=await n.json(),a=JSON.parse(s.contents);if(a&&a.count!==undefined)e.innerText=a.count;else throw new Error("Invalid data")}catch(t){e.innerHTML='<span style="font-size:1rem;color:#e74c3c">Error al conectar con el contador.</span>'}}
